
$ErrorActionPreference="Stop";
if (!(Test-Path ".git")) {
  Write-Host "ERROR: Run this script inside the cloned repository folder, the same folder that contains .git." -ForegroundColor Red;
  Write-Host "Open GitHub Desktop > Show in Explorer, then copy this script there and run it." -ForegroundColor Yellow;
  Read-Host "Press Enter to exit";
  exit 1;
}
$files=@{};
$files["README.md"]=""
$files["main.py"]=""
$files["requirements.txt"]="dWx0cmFseXRpY3MKb3BlbmN2LXB5dGhvbgpwaWxsb3cKcGFuZGFzCm9wZW5weXhsCg=="
$files[".gitignore"]=""
$files["LICENSE"]=""
foreach ($name in $files.Keys) {
  $bytes=[System.Convert]::FromBase64String($files[$name]);
  [System.IO.File]::WriteAllBytes((Join-Path (Get-Location) $name), $bytes);
  Write-Host "Repaired $name" -ForegroundColor Green;
}
Write-Host "";
Write-Host "Done. Now open GitHub Desktop: you should see changed files. Commit and Push." -ForegroundColor Cyan;
Read-Host "Press Enter to exit";
